package main

import (
	"fmt"
	"slices"
	"strings"

	"golang.org/x/tools/imports"
)

// MethodGenerator generates a single method for an annotated struct. Output must be deterministic
// so generated files can be committed and drift-checked in CI.
// Generate receives an ImportsCollector and is expected to register every package it references.
// RenderGenerators uses the collected paths to produce the file's import block.
type MethodGenerator struct {
	Name     string
	Generate func(s *Struct, imports *ImportsCollector) (string, error)
}

// CreateGenerators returns the fixed list of code generators applied to every annotated struct, in the order returned.
// The order determines method ordering in the generated file.
func CreateGenerators() []MethodGenerator {
	return []MethodGenerator{
		ChildMethod,
		ChildCountMethod,
		SetChildrenMethod,
		ReplaceChildMethod,
	}
}

// ImportsCollector accumulates the import paths referenced by generated code.
type ImportsCollector struct {
	used map[string]struct{}
}

func newImportsCollector() *ImportsCollector {
	return &ImportsCollector{used: make(map[string]struct{})}
}

// Add registers an import by absolute path (e.g. "github.com/grafana/mimir/pkg/streamingpromql/planning").
func (c *ImportsCollector) Add(path string) {
	if path == "" {
		return
	}
	c.used[path] = struct{}{}
}

func (c *ImportsCollector) Paths() []string {
	out := make([]string, 0, len(c.used))
	for p := range c.used {
		out = append(out, p)
	}
	slices.Sort(out)
	return out
}

// RenderGenerators produces a complete Go source file applying generators (in the given order) to every annotated struct in pkg.
func RenderGenerators(pkg *Package, generators []MethodGenerator, filename string) ([]byte, error) {
	importsCollector := newImportsCollector()

	var blocks []string
	for _, s := range pkg.NodeStructs {
		for _, g := range generators {
			generatedMethod, err := g.Generate(s, importsCollector)
			if err != nil {
				return nil, fmt.Errorf("failed to generate %s for %s: %w", g.Name, s.Name, err)
			}
			if generatedMethod != "" {
				blocks = append(blocks, generatedMethod)
			}
		}
	}

	if len(blocks) == 0 {
		return []byte{}, nil
	}

	var sb strings.Builder
	sb.WriteString("// Code generated by node-gen. DO NOT EDIT.\n")
	sb.WriteString("// SPDX-License-Identifier: AGPL-3.0-only\n\n")

	fmt.Fprintf(&sb, "package %s\n\n", pkg.Name)
	writeImportBlock(&sb, importsCollector.Paths())

	sb.WriteString(strings.Join(blocks, "\n\n"))
	sb.WriteString("\n")

	return formatSource(sb.String(), filename, false)
}

func writeImportBlock(sb *strings.Builder, paths []string) {
	if len(paths) == 0 {
		return
	}
	sb.WriteString("import (\n")
	for _, p := range paths {
		fmt.Fprintf(sb, "\t%q\n", p)
	}
	sb.WriteString(")\n\n")
}

func receiverName(typeName string) string {
	if typeName == "" {
		return "n"
	}
	return strings.ToLower(typeName[:1])
}

func formatSource(code, filename string, fragment bool) ([]byte, error) {
	imports.LocalPrefix = "github.com/grafana/mimir"
	return imports.Process(filename, []byte(code), &imports.Options{
		Fragment:   fragment,
		FormatOnly: true,
		Comments:   true,
		TabIndent:  true,
		TabWidth:   8,
	})
}
